import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"9、隐者【IX】","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/9、隐者【IX】.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/9、隐者【IX】.md"}'),d={name:"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/9、隐者【IX】.md"};function _(i,a,l,p,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"_9、隐者【ix】",tabindex:"-1"},[s("9、隐者【IX】 "),e("a",{class:"header-anchor",href:"#_9、隐者【ix】","aria-label":'Permalink to "9、隐者【IX】"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调011")])])],-1),o('<h1 id="隐者" tabindex="-1">隐者 <a class="header-anchor" href="#隐者" aria-label="Permalink to &quot;隐者&quot;">​</a></h1><p>隐者之紫</p><p>B+2400<br> 替身外貌：<br> 主体为紫色，替身外表看似荆棘一样的植物。<br> 替身数据：<br> 破坏力D 速度C（闪避防御） 射程D 持续力A 精密动作性D 成长性E<br> 替身对应主属性：感知<br> 替身能力：<br> 情报类替身：隐者之紫并非战斗类替身，只能用于收集情报，因此其破坏力无法提供表现加值，隐者之紫只能视为一根长度为【感知】米且强度等于绳索的荆棘，可以作为肢体的延伸来操控。</p><p>念写：念写具有三种用法，分别为念写照片、念听、念写地图。<br> 念写照片：通过破坏一个照相机的方式念写出一张照片，照片上内容大多暗示着之后的危险，但是也可能只是后续可能遭遇的情况，这视为B级命运本质的类预言效果。这一行为一日只能进行两次。<br> 念听：通过操作电视不停切换频道来连成一句话，也可以靠电视直播自己的脑内情况。<br> 念写地图：消耗一个迅捷动作对面前的炉灰、沙堆等粉末状的物品进行念写来使其变成敏感范围内的地图，并且念写出这个范围内指定事物的位置，视为一种强感知方式，并具有B级特异本质的侦测等级。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
